class Solution { public: ListNode* addNode(ListNode* head, int val) { if (!head) return new ListNode(val); else { head->next = new ListNode(val); return head->next; }} }; 

#include <iostream>
#include <vector>

using namespace std;

 int main() { int n; cin >> n; ListNode *head = NULL; 
 for (int i = 0; i < n; i++) { int val; cin >> val; head = addNode(head, val); } 
 vector<int> ans;
 ListNode* temp = head;
 while (temp) { ans.push_back(temp->val); temp = temp->next; } 
 reverse(ans.begin(), ans.end()); 
 for (auto a : ans) cout << a << ' '; 
 return 0; }
